#include <stdio.h>
#include <stdlib.h>

int main(){
    int T; if(scanf("%d", &T)!=1) return 0;
    while(T--){
        long long N, K; scanf("%lld %lld", &N, &K);
        if(N > K){ printf("-1\n"); continue; }
        int pop = __builtin_popcountll(K);
        if(pop > N){ printf("-1\n"); continue; }
        // counts of exponents 0..25
        long long cnt[26] = {0};
        for(int i=0;i<26;i++) if(K & (1LL<<i)) cnt[i]++;
        long long total = pop;
        while(total < N){
            int e = 25;
            while(e>0 && cnt[e]==0) e--;
            if(e==0) break; // cannot split further
            cnt[e]--;
            cnt[e-1] += 2;
            total++;
        }
        if(total!=N){ printf("-1\n"); continue; }
        // output string
        for(int e=0;e<26;e++){
            while(cnt[e]--) putchar('a'+e);
        }
        putchar('\n');
    }
    return 0;
}

