#include <bits/stdc++.h>
using namespace std;
int main(){
    ios::sync_with_stdio(false);
    cin.tie(nullptr);
    int T; if(!(cin>>T)) return 0;
    while(T--){
        long long N,K; cin>>N>>K;
        if(N>K){ cout<<-1<<'\n'; continue; }
        int pop = __builtin_popcountll(K);
        if(pop> N){ cout<<-1<<'\n'; continue; }
        priority_queue<int> pq;
        for(int i=0;i<26;i++) if(K>>i & 1LL) pq.push(i);
        long long cnt = pop;
        while(cnt<N){
            int e = pq.top(); pq.pop();
            if(e==0) { // cannot split further
                break;
            }
            pq.push(e-1);
            pq.push(e-1);
            ++cnt;
        }
        if(cnt!=N){ cout<<-1<<'\n'; continue; }
        string ans; ans.reserve(N);
        while(!pq.empty()){
            ans.push_back('a'+pq.top());
            pq.pop();
        }
        cout<<ans<<'\n';
    }
    return 0;
}

