#!/usr/bin/env python3
import sys

def solve():
    data = sys.stdin.read().strip().split()
    if not data:
        return
    it = iter(data)
    T = int(next(it))
    out_lines = []
    for _ in range(T):
        N = int(next(it)); K = int(next(it))
        if N > K:
            out_lines.append('-1')
            continue
        pop = K.bit_count()
        if pop > N:
            out_lines.append('-1')
            continue
        # multiset of exponents using a max-heap (negative values)
        import heapq
        heap = []
        for e in range(26):
            if K >> e & 1:
                heapq.heappush(heap, -e)
        cnt = pop
        while cnt < N:
            e = -heapq.heappop(heap)
            if e == 0:
                break
            heapq.heappush(heap, -(e-1))
            heapq.heappush(heap, -(e-1))
            cnt += 1
        if cnt != N:
            out_lines.append('-1')
            continue
        chars = [chr(ord('a') + (-x)) for x in heap]
        out_lines.append(''.join(chars))
    sys.stdout.write('\n'.join(out_lines))

if __name__ == "__main__":
    solve()

